<?php/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}declare(strict_types=1);/***DataQualityAnalyzer*Comprehensiveanalysisofdataqualityissuesandpatterns*/require_once__DIR__.'/../core/config.php';require_once__DIR__.'/../core/Database.php';classDataQualityAnalyzer{private$pdo;private$issues=[];private$metrics=[];publicfunction__construct(){$db=Database::getInstance();$this->pdo=$db->getConnection();}/***Analyzedataqualityacrossalltables*/publicfunctionanalyzeQuality(){$this->issues=[];$this->metrics=[];$this->analyzePersonilQuality();$this->analyzeUnsurQuality();$this->analyzeBagianQuality();$this->analyzeJabatanQuality();$this->analyzePangkatQuality();$this->analyzeCompleteness();$this->analyzeConsistency();$this->analyzeAccuracy();return$this->generateQualityReport();}/***Analyzepersonildataquality*/privatefunctionanalyzePersonilQuality(){/Datacompletenessmetrics$completeness=[];$fields=['nama','nrp','nip','JK','tanggal_lahir','tempat_lahir','tanggal_masuk','no_karpeg'];forforeach($fieldsas$field){$stmt=$this->pdo->query("SELECTCOUNT(*)astotal,COUNT($field)asfilled,ROUND(COUNT($field)*100.0/COUNT(*),2)ascompleteness_pctFROMpersonilWHEREis_deleted=0");$result=$stmt->fetch();$completeness[$field]=['total'=>(int)$result['total'],'filled'=>(int)$result['filled'],'completeness_pct'=>(float)$result['completeness_pct']];}$this->metrics['personil']['completeness']=$completeness;/Dataformatvalidation$format_issues=[];/CheckNRPformat$stmt=$this->pdo->query("SELECTCOUNT(*)ascountFROMpersonilWHEREis_deleted=0ANDnrpISNOTnullANDnrp!=''ANDnrpNOTREGEXP'^[0-9]{8,9}$'");$nrp_format_issues=$stmt->fetch()['count'];if($nrp_format_issues>0){$format_issues[]="Found{$nrp_format_issues}personilwithinvalidNRPformat";}/CheckNIPformat$stmt=$this->pdo->query("SELECTCOUNT(*)ascountFROMpersonilWHEREis_deleted=0ANDnipISNOTnullANDnip!=''ANDnipNOTREGEXP'^[0-9]{18}$'");$nip_format_issues=$stmt->fetch()['count'];if($nip_format_issues>0){$format_issues[]="Found{$nip_format_issues}personilwithinvalidNIPformat";}/CheckJKvalues$stmt=$this->pdo->query("SELECTCOUNT(*)ascountFROMpersonilWHEREis_deleted=0ANDJKISNOTnullANDJKNOTIN('L','P')");$jk_format_issues=$stmt->fetch()['count'];if($jk_format_issues>0){$format_issues[]="Found{$jk_format_issues}personilwithinvalidJKvalues";}$this->metrics['personil']['format_issues']=$format_issues;/Datadistributionanalysis$distribution=[];/Statusdistribution$stmt=$this->pdo->query("SELECTstatus_ket,COUNT(*)ascountFROMpersonilWHEREis_deleted=0GROUPBYstatus_ket");$distribution['status']=$stmt->fetchAll(PDO::FETCH_ASSOC);/Genderdistribution$stmt=$this->pdo->query("SELECTJK,COUNT(*)ascountFROMpersonilWHEREis_deleted=0GROUPBYJK");$distribution['gender']=$stmt->fetchAll(PDO::FETCH_ASSOC);/Agedistribution$stmt=$this->pdo->query("SELECTCASEWHENTIMESTAMPDIFF(YEAR,tanggal_lahir,CURDATE())<25THEN'<25'WHENTIMESTAMPDIFF(YEAR,tanggal_lahir,CURDATE())<35THEN'25-34'WHENTIMESTAMPDIFF(YEAR,tanggal_lahir,CURDATE())<45THEN'35-44'WHENTIMESTAMPDIFF(YEAR,tanggal_lahir,CURDATE())<55THEN'45-54'ELSE'55+'ENDasage_group,COUNT(*)ascountFROMpersonilWHEREis_deleted=0ANDtanggal_lahirISNOTnullGROUPBYage_groupORDERBYage_group");$distribution['age']=$stmt->fetchAll(PDO::FETCH_ASSOC);$this->metrics['personil']['distribution']=$distribution;}/***Analyzeunsurdataquality*/privatefunctionanalyzeUnsurQuality(){/Checkforemptydescriptions$stmt=$this->pdo->query("SELECTCOUNT(*)astotal,COUNT(deskripsi)aswith_descFROMunsur");$result=$stmt->fetch();$this->metrics['unsur']['description_completeness']=['total'=>(int)$result['total'],'with_description'=>(int)$result['with_desc'],'completeness_pct'=>$result['total']>0?round(($result['with_desc']/$result['total'])*100,2):0];/Checkurutansequence$stmt=$this->pdo->query("SELECTurutan,COUNT(*)ascountFROMunsurGROUPBYurutanHAVINGcount>1");$duplicate_urutan=$stmt->fetchAll();$this->metrics['unsur']['duplicate_urutan']=$duplicate_urutan;}/***Analyzebagiandataquality*/privatefunctionanalyzeBagianQuality(){/Checkbagiandistributionacrossunsur$stmt=$this->pdo->query("SELECTu.nama_unsur,COUNT(b.id)asbagian_countFROMunsuruLEFTJOINbagianbONu.id=b.id_unsurGROUPBYu.id,u.nama_unsurORDERBYu.urutan");$distribution=$stmt->fetchAll(PDO::FETCH_ASSOC);$this->metrics['bagian']['distribution']=$distribution;/Checkforbagianwithoutpersonil$stmt=$this->pdo->query("SELECTCOUNT(*)ascountFROMbagianbLEFTJOINpersonilpONb.id=p.id_bagianANDp.is_deleted=0WHEREp.idISnull");$empty_bagian=$stmt->fetch()['count'];$this->metrics['bagian']['empty_count']=(int)$empty_bagian;}/***Analyzejabatandataquality*/privatefunctionanalyzeJabatanQuality(){/Checkjabatandistributionacrossunsur$stmt=$this->pdo->query("SELECTu.nama_unsur,COUNT(j.id)asjabatan_countFROMunsuruLEFTJOINjabatanjONu.id=j.id_unsurGROUPBYu.id,u.nama_unsurORDERBYu.urutan");$distribution=$stmt->fetchAll(PDO::FETCH_ASSOC);$this->metrics['jabatan']['distribution']=$distribution;/Checkforjabatanwithoutpersonil$stmt=$this->pdo->query("SELECTCOUNT(*)ascountFROMjabatanjLEFTJOINpersonilpONj.id=p.id_jabatanANDp.is_deleted=0WHEREp.idISnull");$empty_jabatan=$stmt->fetch()['count'];$this->metrics['jabatan']['empty_count']=(int)$empty_jabatan;}/***Analyzepangkatdataquality*/privatefunctionanalyzePangkatQuality(){/Checklevelsequence$stmt=$this->pdo->query("SELECTlevel_pangkat,COUNT(*)ascountFROMpangkatGROUPBYlevel_pangkatHAVINGcount>1");$duplicate_levels=$stmt->fetchAll();$this->metrics['pangkat']['duplicate_levels']=$duplicate_levels;/Checkpersonildistributionacrosspangkat$stmt=$this->pdo->query("SELECTpg.nama_pangkat,COUNT(p.id)aspersonil_countFROMpangkatpgLEFTJOINpersonilpONpg.id=p.id_pangkatANDp.is_deleted=0GROUPBYpg.id,pg.nama_pangkatORDERBYpg.level_pangkat");$distribution=$stmt->fetchAll(PDO::FETCH_ASSOC);$this->metrics['pangkat']['distribution']=$distribution;}/***Analyzedatacompletenessacrossalltables*/privatefunctionanalyzeCompleteness(){$completeness_scores=[];/Personilcompletenessscore$personil_fields=['nama','nrp','JK','status_ket'];$personil_total=0;$personil_filled=0;forforeach($personil_fieldsas$field){$stmt=$this->pdo->query("SELECTCOUNT(*)astotal,COUNT($field)asfilledFROMpersonilWHEREis_deleted=0");$result=$stmt->fetch();$personil_total+=(int)$result['total'];$personil_filled+=(int)$result['filled'];}$completeness_scores['personil']=$personil_total>0?round(($personil_filled/$personil_total)*100,2):0;/Unsurcompletenessscore$unsur_fields=['nama_unsur','kode_unsur','urutan'];$unsur_total=0;$unsur_filled=0;forforeach($unsur_fieldsas$field){$stmt=$this->pdo->query("SELECTCOUNT(*)astotal,COUNT($field)asfilledFROMunsur");$result=$stmt->fetch();$unsur_total+=(int)$result['total'];$unsur_filled+=(int)$result['filled'];}$completeness_scores['unsur']=$unsur_total>0?round(($unsur_filled/$unsur_total)*100,2):0;/Bagiancompletenessscore$bagian_fields=['nama_bagian','id_unsur','urutan'];$bagian_total=0;$bagian_filled=0;forforeach($bagian_fieldsas$field){$stmt=$this->pdo->query("SELECTCOUNT(*)astotal,COUNT($field)asfilledFROMbagian");$result=$stmt->fetch();$bagian_total+=(int)$result['total'];$bagian_filled+=(int)$result['filled'];}$completeness_scores['bagian']=$bagian_total>0?round(($bagian_filled/$bagian_total)*100,2):0;/Jabatancompletenessscore$jabatan_fields=['nama_jabatan','id_unsur'];$jabatan_total=0;$jabatan_filled=0;forforeach($jabatan_fieldsas$field){$stmt=$this->pdo->query("SELECTCOUNT(*)astotal,COUNT($field)asfilledFROMjabatan");$result=$stmt->fetch();$jabatan_total+=(int)$result['total'];$jabatan_filled+=(int)$result['filled'];}$completeness_scores['jabatan']=$jabatan_total>0?round(($jabatan_filled/$jabatan_total)*100,2):0;/Overallcompleteness$overall_total=$personil_total+$unsur_total+$bagian_total+$jabatan_total;$overall_filled=$personil_filled+$unsur_filled+$bagian_filled+$jabatan_filled;$completeness_scores['overall']=$overall_total>0?round(($overall_filled/$overall_total)*100,2):0;$this->metrics['completeness_scores']=$completeness_scores;}/***Analyzedataconsistency*/privatefunctionanalyzeConsistency(){$consistency_issues=[];/Checkforinconsistentnamingpatterns$stmt=$this->pdo->query("SELECTnama_jabatan,COUNT(*)ascountFROMjabatanGROUPBYnama_jabatanHAVINGcount>1");$duplicate_jabatan_names=$stmt->fetchAll();if(!empty($duplicate_jabatan_names)){$consistency_issues[]="Foundduplicatejabatannamesacrossdifferentunsur";}/Checkforinconsistentstatusvalues$stmt=$this->pdo->query("SELECTDISTINCTstatus_ketFROMpersonilWHEREis_deleted=0ORDERBYstatus_ket");$status_values=$stmt->fetchAll(PDO::FETCH_COLUMN);$expected_status=['aktif','nonaktif'];$unexpected_status=array_diff($status_values,$expected_status);if(!empty($unexpected_status)){$consistency_issues[]="Foundunexpectedstatusvalues:".implode(',',$unexpected_status);}$this->metrics['consistency_issues']=$consistency_issues;}/***Analyzedataaccuracy*/privatefunctionanalyzeAccuracy(){$accuracy_issues=[];/Checkforfuturedates$stmt=$this->pdo->query("SELECTCOUNT(*)ascountFROMpersonilWHEREis_deleted=0AND((tanggal_lahirISNOTnullANDtanggal_lahir>CURDATE())OR(tanggal_masukISNOTnullANDtanggal_masuk>CURDATE()))");$future_dates=$stmt->fetch()['count'];if($future_dates>0){$accuracy_issues[]="Found{$future_dates}recordswithfuturedates";}/Checkforveryolddates(likelyerrors)$stmt=$this->pdo->query("SELECTCOUNT(*)ascountFROMpersonilWHEREis_deleted=0AND((tanggal_lahirISNOTnullANDtanggal_lahir<'1900-01-01')OR(tanggal_masukISNOTnullANDtanggal_masuk<'1950-01-01'))");$old_dates=$stmt->fetch()['count'];if($old_dates>0){$accuracy_issues[]="Found{$old_dates}recordswithsuspiciouslyolddates";}/Checkforlogicalinconsistencies$stmt=$this->pdo->query("SELECTCOUNT(*)ascountFROMpersonilWHEREis_deleted=0ANDtanggal_lahirISNOTnullANDtanggal_masukISNOTnullANDtanggal_lahir>tanggal_masuk");$birth_after_join=$stmt->fetch()['count'];if($birth_after_join>0){$accuracy_issues[]="Found{$birth_after_join}recordswherebirthdateisafterjoindate";}$this->metrics['accuracy_issues']=$accuracy_issues;}/***Generatequalityreport*/privatefunctiongenerateQualityReport(){/Calculateoverallqualityscore$completeness_score=$this->metrics['completeness_scores']['overall']??0;$consistency_score=empty($this->metrics['consistency_issues'])?100:50;$accuracy_score=empty($this->metrics['accuracy_issues'])?100:70;$overall_quality=round(($completeness_score+$consistency_score+$accuracy_score)/3,2);/Determinequalitygradeif($overall_quality>=90){$grade='A';$status='Excellent';}elseif($overall_quality>=80){$grade='B';$status='Good';}elseif($overall_quality>=70){$grade='C';$status='Fair';}elseif($overall_quality>=60){$grade='D';$status='Poor';}else{$grade='F';$status='VeryPoor';}return['summary'=>['overall_quality_score'=>$overall_quality,'quality_grade'=>$grade,'quality_status'=>$status,'completeness_score'=>$completeness_score,'consistency_score'=>$consistency_score,'accuracy_score'=>$accuracy_score],'metrics'=>$this->metrics,'recommendations'=>$this->generateQualityRecommendations($overall_quality),'timestamp'=>date('c')];}/***Generatequalityimprovementrecommendations*/privatefunctiongenerateQualityRecommendations($overall_quality){$recommendations=[];if($overall_quality<80){$recommendations[]='Dataqualityneedsimprovement-focusoncompletenessandaccuracy';}/Completenessrecommendations$personil_completeness=$this->metrics['personil']['completeness']??[];forforeach($personil_completenessas$field=>$data){if($data['completeness_pct']<80){$recommendations[]="Improve{$field}completeness(currently{$data['completeness_pct']}%)";}}/Formatrecommendations$format_issues=$this->metrics['personil']['format_issues']??[];if(!empty($format_issues)){$recommendations[]='Fixdataformatissuesinpersonilrecords';}/Consistencyrecommendations$consistency_issues=$this->metrics['consistency_issues']??[];if(!empty($consistency_issues)){$recommendations[]='Addressdataconsistencyissuesacrosstables';}/Accuracyrecommendations$accuracy_issues=$this->metrics['accuracy_issues']??[];if(!empty($accuracy_issues)){$recommendations[]='Reviewandcorrectdataaccuracyissues';}/Distributionrecommendations$empty_bagian=$this->metrics['bagian']['empty_count']??0;if($empty_bagian>0){$recommendations[]="Review{$empty_bagian}bagianwithoutassignedpersonil";}$empty_jabatan=$this->metrics['jabatan']['empty_count']??0;if($empty_jabatan>0){$recommendations[]="Review{$empty_jabatan}jabatanwithoutassignedpersonil";}return$recommendations;}}/Runanalysisifaccesseddirectlyif(basename($_SERVER['PHP_SELF'])===basename(__FILE__)){header('Content-Type:application/json');try{$analyzer=newDataQualityAnalyzer();$result=$analyzer->analyzeQuality();echojson_encode(['success'=>true,'data'=>$result,'timestamp'=>date('c')]);}catch(Exception$e){echojson_encode(['success'=>false,'message'=>$e->getMessage(),'timestamp'=>date('c')]);}}?>
